package com.veetu.vadagai.common;import jakarta.validation.ConstraintViolationException;import org.springframework.http.*;import org.springframework.web.bind.MethodArgumentNotValidException;import org.springframework.web.bind.annotation.*;import java.util.Map;import java.util.stream.Collectors;
@RestControllerAdvice public class GlobalExceptionHandler{@ExceptionHandler(MethodArgumentNotValidException.class) ResponseEntity<ApiResponse<Map<String,String>>> validation(MethodArgumentNotValidException ex){var errors=ex.getBindingResult().getFieldErrors().stream().collect(Collectors.toMap(e->e.getField(),e->e.getDefaultMessage()==null?"Invalid":e.getDefaultMessage(),(a,b)->a));return ResponseEntity.badRequest().body(ApiResponse.fail("Validation failed",errors));}@ExceptionHandler({IllegalArgumentException.class,ConstraintViolationException.class}) ResponseEntity<ApiResponse<Void>> bad(Exception ex){return ResponseEntity.badRequest().body(ApiResponse.fail(ex.getMessage(),null));}@ExceptionHandler(Exception.class) ResponseEntity<ApiResponse<Void>> err(Exception ex){return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).body(ApiResponse.fail("Unexpected server error",null));}}
